const LATEST = FLOW[FLOW.length - 1];
function fmtCZ(iso) { const [y, m, d] = iso.split("-").map(Number); return d + ". " + m + ". " + y; }
const HABIT_DATE = fmtCZ(LATEST.d);
const HABIT_STATS = (() => {
  const days = FLOW.length;
  const totalC = FLOW.reduce((s, e) => s + e.c, 0);
  const avg = Math.round((totalC / (days * 9)) * 100);
  const perfect = FLOW.filter((e) => e.c === 9).length;
  const totals = HABIT_DEFS.map((_, j) => FLOW.reduce((s, e) => s + e.h[j], 0));
  const streaks = HABIT_DEFS.map((_, j) => { let s = 0; for (let i = FLOW.length - 1; i >= 0; i--) { if (FLOW[i].h[j]) s++; else break; } return s; });
  return { days, avg, perfect, totals, streaks };
})();
function hexA(hex, a) { const h = hex.replace("#", ""); const r = parseInt(h.slice(0, 2), 16), g = parseInt(h.slice(2, 4), 16), b = parseInt(h.slice(4, 6), 16); return `rgba(${r},${g},${b},${a})`; }
