// commit on blur/Enter · Escape reverts
function BufferedInput({ value, onCommit, style, placeholder }) {
  const [v, setV] = useState(value);
  React.useEffect(() => setV(value), [value]);
  const commit = () => { const nv = v.trim(); if (nv && nv !== value) onCommit(nv); else setV(value); };
  return <input value={v} onChange={(e) => setV(e.target.value)} onBlur={commit} onKeyDown={(e) => { if (e.key === "Enter") e.currentTarget.blur(); if (e.key === "Escape") { setV(value); e.currentTarget.blur(); } }} placeholder={placeholder} style={{ background: "transparent", border: "none", outline: "none", padding: 0, width: "100%", ...style }} />;
}

// upload a compressed cover/icon dataURL into pageMeta
function makePagePicker(st, pageKey, field, maxSide) {
  return () => {
    const inp = document.createElement("input");
    inp.type = "file"; inp.accept = "image/*";
    inp.onchange = async () => {
      const f = inp.files && inp.files[0];
      if (!f) return;
      try {
        const old = st.pageMetaOf(pageKey)[field];
        const blob = await resizeImageToBlob(f, maxSide);
        const id = uid() + (field === "icon" ? "i" : "c");
        await r2Put(id, blob, f.name);
        st.setPageMeta(pageKey, { [field]: { r2id: id } });
        if (old && old.r2id) r2Del(old.r2id);
      }
      catch (e) { st.ask(L("Obrázek se nepodařilo načíst.", "Couldn't load the image."), null); }
    };
    inp.click();
  };
}

function PageTitle({ icon, children, kicker, pageKey }) {
  const { t } = useT();
  const st = useStore();
  const meta = pageKey ? st.pageMetaOf(pageKey) : {};
  const title = meta.title || children;
  const kick = meta.kicker || kicker;
  const editable = pageKey && st.editMode;
  const cover = meta.cover;
  const customIcon = meta.icon; // dataURL overrides the passed-in icon
  const pickCover = pageKey ? makePagePicker(st, pageKey, "cover", 1400) : null;
  const pickIcon = pageKey ? makePagePicker(st, pageKey, "icon", 240) : null;
  const h1Style = { fontFamily: FONT_DISPLAY, fontWeight: 300, fontSize: 46, lineHeight: 1.1, color: t.heading, margin: 0, display: "flex", alignItems: "center", gap: 14 };
  const iconNode = customIcon
    ? <img src={imgSrc(customIcon)} alt="" style={{ width: 46, height: 46, borderRadius: 11, objectFit: "cover", display: "block", flexShrink: 0 }} />
    : (icon && (typeof icon === "string" ? <span style={{ fontSize: 38 }}>{icon}</span> : icon));
  const ctrl = { background: hexA(t.mode === "light" ? "#1C1C1A" : "#000000", 0.42), border: "none", borderRadius: 7, color: "#F4F0EB", cursor: "pointer", padding: "4px 10px", fontFamily: FONT_BODY, fontSize: 12, backdropFilter: "blur(4px)" };
  return (
    <div>
      {cover && (
        <div style={{ margin: "-48px -36px 0", position: "relative" }}>
          <div style={{ height: 200, overflow: "hidden", position: "relative" }}>
            <img src={imgSrc(cover)} alt="" style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
            <div style={{ position: "absolute", inset: 0, background: `linear-gradient(180deg, transparent 52%, ${hexA(t.bg, 0.75)} 100%)` }} />
            {editable && (
              <div style={{ position: "absolute", top: 12, right: 40, display: "flex", gap: 6 }}>
                <button onClick={pickCover} style={ctrl}>{L("Změnit pozadí", "Change cover")}</button>
                <button onClick={() => { if (cover && cover.r2id) r2Del(cover.r2id); st.setPageMeta(pageKey, { cover: "" }); }} style={ctrl}>Odebrat</button>
              </div>
            )}
          </div>
        </div>
      )}
      <div style={{ marginBottom: 8, marginTop: cover ? 12 : 0 }}>
        {editable && (
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 10 }}>
            <button onClick={pickIcon} style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "4px 11px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 12.5 }}>{customIcon ? L("Změnit ikonu", "Change icon") : L("Nahrát ikonu", "Upload icon")}</button>
            {customIcon && <button onClick={() => st.setPageMeta(pageKey, { icon: "" })} style={{ background: "transparent", border: `1px solid ${t.borderSoft}`, borderRadius: 8, padding: "4px 11px", cursor: "pointer", color: t.textMuted, fontFamily: FONT_BODY, fontSize: 12.5 }}>{L("Výchozí ikona", "Default icon")}</button>}
            {!cover && <button onClick={pickCover} style={{ background: "transparent", border: `1px dashed ${t.border}`, borderRadius: 8, padding: "4px 11px", cursor: "pointer", color: t.sand, fontFamily: FONT_BODY, fontSize: 12.5 }}>{L("Nastavit horní pozadí", "Set cover image")}</button>}
          </div>
        )}
        {editable
          ? <div style={{ marginBottom: 14 }}><BufferedInput value={kick || ""} onCommit={(v) => st.setPageMeta(pageKey, { kicker: v })} placeholder="kicker…" style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.22em", fontSize: 12, color: t.accent, borderBottom: `1px dashed ${t.borderSoft}` }} /></div>
          : (kick && <Eyebrow>{kick}</Eyebrow>)}
        <h1 style={h1Style}>
          {iconNode}
          {editable
            ? <BufferedInput value={typeof title === "string" ? title : ""} onCommit={(v) => st.setPageMeta(pageKey, { title: v })} placeholder={L("Název stránky…", "Page title…")} style={{ ...h1Style, display: "block", borderBottom: `1px dashed ${t.borderSoft}` }} />
            : title}
        </h1>
      </div>
    </div>
  );
}

