function OfflineBadge() {
  const { t } = useT();
  const [online, setOnline] = useState(typeof navigator !== "undefined" ? navigator.onLine : true);
  React.useEffect(() => {
    const on = () => setOnline(true), off = () => setOnline(false);
    window.addEventListener("online", on);
    window.addEventListener("offline", off);
    return () => { window.removeEventListener("online", on); window.removeEventListener("offline", off); };
  }, []);
  if (online) return null;
  return (
    <div
      title={L("Jsi offline. Změny se uloží a synchronizují po připojení. Média se načtou jen u stránek uložených offline.", "You are offline. Changes save and sync once you reconnect. Media loads only for pages saved offline.")}
      style={{ position: "fixed", left: 16, bottom: 16, zIndex: 9999, display: "inline-flex", alignItems: "center", gap: 7, background: t.card, border: `1px solid ${t.border}`, borderRadius: 999, padding: "6px 13px", boxShadow: "0 6px 20px rgba(0,0,0,0.28)", fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.1em", fontSize: 10.5, color: t.textMuted }}
    >
      <span style={{ width: 7, height: 7, borderRadius: "50%", background: t.sand, flexShrink: 0 }} />
      {L("Offline", "Offline")}
    </div>
  );
}

/** Vědomé sdílení: snímek počítá aplikace sama a jen z toho, co klient zapnul.
 *  Návyky = posledních 30 dní zaškrtnutí, cíle = názvy a stavy. Nic víc neodchází. */
function buildShareSnapshot(coll, edits) {
  const share = (coll && coll.share) || {};
  if (!share.habits && !share.goals && !share.training) return null;
  const out = { at: Date.now() };
  if (share.habits) {
    const defs = ((coll.habitDefs || HABIT_DEFAULTS) || []).filter((x) => !x.archived).map((x) => ({ slot: x.slot, icon: x.icon, name: x.name }));
    const days = {};
    const now = Date.now();
    for (let i = 0; i < 30; i++) {
      const d = new Date(now - i * 86400000).toISOString().slice(0, 10);
      const e = edits && edits[d];
      if (e && e.h) days[d] = e.h;
    }
    out.habits = { defs, days };
  }
  if (share.goals) {
    out.goals = (coll.userGoals || []).map((g) => ({
      name: g.name, area: g.area || "",
      status: ((coll.goals || {})[g.name] != null ? (coll.goals || {})[g.name] : g.status) || "",
    }));
  }
  if (share.training) {
    // Jen splněno a kdy. Žádné poznámky, žádná váha, žádný pocit.
    out.training = { plans: coll.trDone || {}, sched: coll.trSched || {} };
  }
  return out;
}

/** Vstupní brána — nový příchozí zadá slovo od Tanyho. Jednou provždy. */
function InviteGate() {
  const [word, setWord] = useState("");
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState(false);
  const submit = async () => {
    if (!word.trim() || busy) return;
    setBusy(true); setErr(false);
    try {
      const r = await fetch("/api/join", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ word }) });
      if (r.ok) { window.location.reload(); return; }
    } catch (e) {}
    setErr(true); setBusy(false);
  };
  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 400, background: "#1A1612", display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
      <div style={{ width: "100%", maxWidth: 440, textAlign: "center" }}>
        <div style={{ fontFamily: FONT_DISPLAY, fontWeight: 300, fontSize: 44, color: "#F4F0EB", letterSpacing: "0.04em" }}>
          t<span style={{ position: "relative" }}>a<Bindu size={5} style={{ position: "absolute", top: 6, left: 4 }} /></span>nmay
        </div>
        <div style={{ fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.3em", fontSize: 11, color: "#B87333", marginTop: 16 }}>
          {L("Vstup do praxe", "Entering the practice")}
        </div>
        <div style={{ fontFamily: FONT_BODY, fontSize: 14.5, color: "#BFB0A3", lineHeight: 1.7, margin: "16px auto 28px", maxWidth: "26em" }}>
          {L("Tento prostor se otevírá slovem, které dostaneš ode mě. Pokud ho ještě nemáš, ozvi se — začíná to rozhovorem.",
             "This space opens with a word you receive from me. If you don't have it yet, reach out — it begins with a conversation.")}
        </div>
        <input
          value={word}
          onChange={(e) => { setWord(e.target.value); setErr(false); }}
          onKeyDown={(e) => { if (e.key === "Enter") submit(); }}
          placeholder={L("vstupní slovo", "the word")}
          autoFocus
          style={{ width: "100%", boxSizing: "border-box", background: "#24221D", border: `1px solid ${err ? "#B87333" : "rgba(124,140,110,0.3)"}`, borderRadius: 10, padding: "14px 18px", color: "#F4F0EB", fontFamily: FONT_BODY, fontSize: 16, textAlign: "center", outline: "none" }}
        />
        {err && (
          <div style={{ fontFamily: FONT_BODY, fontSize: 12.5, color: "#B87333", marginTop: 10 }}>
            {L("To není ono. Zkus to znovu, nebo mi napiš.", "Not quite. Try again, or write to me.")}
          </div>
        )}
        <button onClick={submit} disabled={busy} style={{ marginTop: 22, background: "#B87333", color: "#1C1C1A", border: "none", borderRadius: 100, padding: "13px 42px", cursor: busy ? "default" : "pointer", opacity: busy ? 0.6 : 1, fontFamily: FONT_TAG, textTransform: "uppercase", letterSpacing: "0.24em", fontSize: 12.5 }}>
          {busy ? L("Otevírám…", "Opening…") : L("Vstoupit", "Enter")}
        </button>
        <div style={{ fontFamily: FONT_BODY, fontStyle: "italic", fontSize: 12, color: "#8C7B6E", marginTop: 30 }}>
          Trust the body. Hold the practice. Listen to the wild.
        </div>
      </div>
    </div>
  );
}

